+
+fn generate_valid_token(signing_key: &Ed25519SigningKey, cap: &str) -> CapabilityToken {
+    let now = Utc::now();
+    let cose = CapabilityTokenBuilder::new()
+        .capability_id(cap)
+        .zone_id("z:work")
+        .principal("user:test")
+        .operations(&[cap])
+        .issuer("node:test")
+        .validity(now, now + Duration::hours(1))
+        .sign(signing_key)
+        .unwrap();
+    CapabilityToken { raw: cose }
+}
+
+async fn setup_handshake(connector: &mut PineconeConnector, caps: &[&str]) -> Ed25519SigningKey {
+    let signing_key = Ed25519SigningKey::generate();
+    let verifying_key = signing_key.verifying_key();
+
+    connector
+        .handle_handshake(json!({
+            "protocol_version": "1.0.0",
+            "zone": "z:work",
+            "host_public_key": verifying_key.to_bytes(),
+            "nonce": vec![0u8; 32],
+            "capabilities_requested": caps
+        }))
+        .await
+        .expect("handshake should succeed");
+
+    signing_key
+}
+
+async fn setup_configure(connector: &mut PineconeConnector, control_url: &str, data_url: &str) {
+    connector
+        .handle_configure(json!({
+            "api_key": "test-key-xyz",
+            "control_plane_url": control_url,
+            "data_plane_url": data_url
+        }))
+        .await
+        .expect("configure should succeed");
+}
